public int minSeconds(int[] amount) {
    int total = amount[0] + amount[1] + amount[2];
    int largestTwo = Math.max(amount[0] + amount[1], Math.max(amount[1] + amount[2], amount[0] + amount[2]));
    return (total + 1) / 2 - (largestTwo + 1) / 2 + largestTwo;
}
```

